import {PromiseUtils as Async} from 'jibo-cai-utils';
import {Reply, Request, EventMessage, MessageBase, MessageError} from './SocketTypes';
import {EventEmitter} from 'events';
import ClientRemoteObject from './ClientRemoteObject';
import WSClient from './WSClient';

import parentLog from './log';
const log = parentLog.createChild('RemoteClient');

interface MessageMap {
    event:(message:EventMessage) => void;
    reply:(message:Reply) => void;
    request:(message:Request) => void;
    error:(message:MessageError) => void;
}

export type CallbackHandler = (data:any) => void;
export type RejectionHandler = (err) => void;


export default class RemoteClient extends EventEmitter {

    private static _messageId:number = 0;

    public instances:Map<number, ClientRemoteObject> = new Map<number, any>();
    protected _callbackHandlers:Map<number, CallbackHandler> = new Map<number, CallbackHandler>();
    protected _rejectionHandlers:Map<number, RejectionHandler> = new Map<number, RejectionHandler>();

    private _isInitialized:boolean = false;
    private _client:WSClient;
    private _messageMap:MessageMap;
    private port:number;

    constructor(private token:string) {
        super();
        this.onMessage = this.onMessage.bind(this);
        this._messageMap = {
            event: this.onEvent.bind(this),
            reply: this.onReply.bind(this),
            request: this.onRequest.bind(this),
            error: this.onError.bind(this)
        };
    }

    public async init(port:number = 11111):Promise<void> {
        if(this._isInitialized) {
            return;
        }
        this.port = port;
        this._isInitialized = true;
        this._client = new WSClient(`ws://127.0.0.1:${this.port}`);
        this._client.on('reopen', () => {
            this.emit('reopen');
        });
        this._client.on('message', this.onMessage);
        await Async.promisify<void>(cb => this._client.on('open', cb));
    }

    public async sendMessage<T>(instanceId:number, methodName:string, args:any[] = [], sendAndForget:boolean = false):Promise<T> {
        const data:Request = {
            type: 'request',
            messageId: this.getMessageId(),
            instanceId,
            methodName,
            args,
            sendAndForget
        };
        this._client.send(JSON.stringify(data));
        if(!sendAndForget) {
            return await this.waitForReply<T>(data.messageId);
        }
    }

    public destroy():void {
        if(this._client) {
            this._client.removeListener('message', this.onMessage);
            this._client = undefined;
        }
    }

    /**
     * @param messageId The message handle
     * @returns Promise that resolves to the return value
     */
    private waitForReply<T>(messageId:number):Promise<T> {
        return new Promise<T>((resolve:(ret:T) => void, reject) => {
            this._callbackHandlers.set(messageId, (value:T) => {
                resolve(value);
            });
            this._rejectionHandlers.set(messageId, (err) => {
                reject(err);
            });
        });
    }

    private onMessage(messageBase:MessageBase):void {
        this._messageMap[messageBase.type](messageBase);
    }

    private onEvent(message:EventMessage) {
        const instance = this.instances[message.instanceId];
        if(!instance) {
            log.warn(`Cannot emit event ${message.args[0]} on instance id ${message.instanceId}`);
        }
        else if(instance instanceof EventEmitter) {
            (instance as EventEmitter).emit.apply(instance, message.args);
        }
        else {
            throw new Error(`Tried to emit an event on ${instance}, but
                it's not an EventEmitter`);
        }
    }

    private async onRequest(message:Request) {
        try {
            const instance = this.instances[message.instanceId];
            if(!instance) {
                log.warn(`Could not call method ${message.methodName} on id ${message.instanceId} with args ${message.args}`);
                return;
            }
            const ret = await instance[message.methodName].apply(instance, message.args);
            if(!message.sendAndForget) {
                const reply:Reply = {
                    type: 'reply',
                    messageId: message.messageId,
                    value: ret
                };
                this._client.send(JSON.stringify(reply));
            }
        }
        catch(err) {
            let messageText = 'Unspeficied Error';
            if(err instanceof Error) {
                messageText = err.message;
            }
            else if(typeof err === 'string') {
                messageText = err;
            }
            const errorMessage:MessageError = {
                type: 'error',
                messageId: message.messageId,
                message: messageText
            };
            log.error(errorMessage);
            this._client.send(JSON.stringify(errorMessage));
        }
    }

    private onReply(message:Reply) {
        if(this._callbackHandlers.has(message.messageId)) {
            this._callbackHandlers.get(message.messageId)(message.value);
            this._callbackHandlers.delete(message.messageId);
            this._rejectionHandlers.delete(message.messageId);
        }
    }

    private onError(message:MessageError) {
        if(this._rejectionHandlers.has(message.messageId)) {
            this._rejectionHandlers.get(message.messageId)(message.message);
            this._callbackHandlers.delete(message.messageId);
            this._rejectionHandlers.delete(message.messageId);
        }
    }

    private getMessageId():number {
        return RemoteClient._messageId++;
    }
}
