import WebSocket = require('ws-without-native');
import {EventEmitter} from "events";

import parentLog from './log';
const log = parentLog.createChild('WSClient');
/**
 * HTTP WebSocket Client
 * @class HTTPWSClient
 * @extends EventEmitter
 * @param {String} host
 */
class HTTPWSClient extends EventEmitter {

    /**
     * The socket connection.
     * @name HTTPWSClient#socket
     * @type {WebSocket}
     */
    public socket:WebSocket;
    private isReconnecting:boolean = false;

    constructor(public host:string) {
        super();
        this.onStartReconnect = this.onStartReconnect.bind(this);
        this.onError = this.onError.bind(this);
        this.onClose = this.onClose.bind(this);
        this.onMessage = this.onMessage.bind(this);
        this.connect = this.connect.bind(this);
        this.onOpen = this.onOpen.bind(this);
        this.connect();
    }

    /**
     * Send data.
     * @method HTTPWSClient#send
     * @param {String|Object} json Either raw data or data object.
     */
    public send(json:string|Object):void {
        if (typeof json !== 'string') {
            try {
                json = JSON.stringify(json);
            }
            catch (e) {
                log.error('JSON.stringify: ', e);
                json = null;
            }
        }
        if(this.socket) {
            this.socket.send(json);
        }
    }

    private connect():void {
        log.debug('connect');
        this.socket = new WebSocket(this.host, <any>{perMessageDeflate: false});
        this.socket.on('error', this.onError);
        this.socket.on('close', this.onClose);
        this.socket.on('message', this.onMessage);
        this.socket.on('open', this.onOpen);
    }

    /**
     * Called when there is an error to try reconnect
     */
    private onStartReconnect():void {
        this.isReconnecting = true;
        this.socket.removeAllListeners();
        this.socket = null;
        setTimeout(this.connect, 1000);
    }

    private onError(err: Error):void {
        log.warn('socket error', err);
        this.onStartReconnect();
    }

    private onClose(code:number, message:string):void {
        log.warn('socket closed', code, message);
        this.emit('close');
        this.onStartReconnect();
    }

    private onMessage(data:string):void {
        let command:any;
        try {
            // TOFIX: Take this out when the platform service
            // fixes on their end; really should throw an error when we receive NaN.
            command = JSON.parse(data.replace(/\bNaN\b/g, "0"));
        }
        catch(e) {
            const r:RegExp = /at position (\d+)/g;
            const result:RegExpExecArray = r.exec(e.message);
            if (data.length < 500) {
                if(result) {
                    let pos:number = parseInt(result[1]);    
                    log.error('Invalid JSON sent to jibo client on host ' + this.host + ' at position ' + pos, data);
                }
                else {
                    log.error('Invalid JSON sent to jibo client on host ' + this.host, data);
                }
            } 
            else {
                if(result) {
                    const padding = 250;
                    let pos:number = parseInt(result[1]);
                    data = data.substr(Math.max(0, pos - padding), Math.min(data.length - 1, pos + padding));
                    if(pos > padding) {
                        pos = padding;
                    }
                    log.error('Invalid JSON sent to jibo client on host' + this.host + ' at position ' + pos  + ' of snippet', data);
                }
                else {
                    log.error('Invalid JSON sent to jibo client on host ' + this.host);                    
                }
                
            }
            // this.emit('error','json ' + e, data);
        }
        //if the JSON parse succeeded, send the message
        //if this is inside the try, then if someone has an error up the chain we swallow it
        //and pretend that it is bad JSON
        if (command) {
            this.emit('message', command);
        }
    }

    private onOpen():void {
        this.emit('open');
        if(this.isReconnecting) {
            this.isReconnecting = false;
            this.emit('reopen');
        }
    }
}

export default HTTPWSClient;
