import {EventEmitter} from 'events';
import WSClient from './WSClient';
import RegistryClient from './RegistryClient';
import RegistrationRecord from './RegistrationRecord';

import parentLog from './log';
const log = parentLog.createChild('NotificationsDispatcher');


export type ErrCallback = (err?:Error)=>void;

// see also https://confluence.jibo.com/display/SER/Robot+Notifications
interface NotificationMessage {
    _id:string;
    skillId:string;
    payload:Payload;
    created:string;
}

interface Payload {
    name:string;
    payload:any;
}

const enum Status {
    Invalid,      // 0
    Connected,    // 1
    Disconnected  // 2
};

interface StatusMessage {
    status:Status;
}

type RecordCallback = (err?:Error, record?:RegistrationRecord)=>void;


class NotificationsDispatcher extends EventEmitter {
    private notificationsSocket:WSClient;
    private statusSocket:WSClient;
    private lastStatus:number;

    constructor(host?:string, port?:number) {
        super();
        // If RegistryClient.instance isn't already created, a host and port
        // can be passed in here, in which case we create one
        if( !RegistryClient.instance && host && port) {
            RegistryClient.createInstance(host, port);
        }
    }

    public init(callback:ErrCallback) {
        RegistryClient.instance.getRecordByName('server',
            (err, record:RegistrationRecord) => {
                log.iferr(err, 'Error getting "server" service record');
                if(!err) {
                    this._setupSockets(`ws://${record.host}:${record.port}`);
                }
                callback(err);
            });
    }


    private _processNotification(message:NotificationMessage) {
        log.info('process notification', message);
        if (message && message.payload && message.payload.name) {
            log.info('emitting', message.payload.name, message.payload.payload);
            this.emit(message.payload.name, message.payload.payload);
        }
    }


    private _processStatus(message:StatusMessage) {
        // NOTE: this intentionally ignores status of 0 ("Invalid")
        if (message && message.status) {
            // status reports stream out at 1Hz. only emit events on status changes.
            if (message.status !== this.lastStatus) {
                this.lastStatus = message.status;
                this.emit('StatusChanged', message.status);
                if (message.status === 1) {
                    this.emit('StatusConnected');
                }
                if (message.status === 2) {
                    this.emit('StatusDisconnected');
                }
            }
        }
    }


    private _setupSockets(url) {
        if (!this.notificationsSocket) {
            let socketUrl = url + '/server/notifications';
            this.notificationsSocket = new WSClient(socketUrl);
            this.notificationsSocket.on('message', this._processNotification.bind(this));
        }

        if (!this.statusSocket) {
            let socketUrl = url + '/server/notifications/status';
            this.statusSocket = new WSClient(socketUrl);
            this.statusSocket.on('message', this._processStatus.bind(this));
        }
    }
}

export default NotificationsDispatcher;
